return-response.set-body:
@{
                        var code = context.Response.StatusCode;
                        var err = context.LastError;
                        var msg = err != null && !string.IsNullOrEmpty(err.Message)
                            ? err.Message
                            : (code == 401
                                ? "Missing or invalid APIM subscription key. Include header 'Ocp-Apim-Subscription-Key: ' or query string '?subscription-key='."
                                : "Access denied.");
                        var error = code == 401 ? "unauthorized" : "forbidden";
                        return Newtonsoft.Json.JsonConvert.SerializeObject(new {
                            error = error,
                            status = code,
                            message = msg
                        });
                    }

@{
                        var err = context.LastError;
                        var msg = err != null ? err.Message : "Unknown error loading contracts";
                        return Newtonsoft.Json.JsonConvert.SerializeObject(new {
                            error = "internal_error",
                            status = 500,
                            message = msg
                        });
                    }
